Let me outline the plan before implementation:

**Plan for a Single-file Snake Game:**

1. **HTML Structure**
   - A centered container
   - Title, score display, game area (`<canvas>`), “Game Over” overlay and a restart button

2. **CSS Styling**
   - Responsive, centered game area
   - Stylish UI (rounded corners, shadows, colors)
   - Overlay for “Game Over” with a restart button

3. **JavaScript Functionality**
   - Game loop, snake movement, food generation
   - Arrow key controls with no reverse into itself
   - Score tracking and display
   - Game over logic with overlay
   - Restart button resets game state

4. **Testing**
   - Playable, smooth controls, restarts, score increments

---

Next, I’ll generate the full `index.html` containing all HTML, CSS, and JS inline, fulfilling all feature and style requirements.

---

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Snake Game</title>
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <style>
    body {
      background: linear-gradient(120deg, #232526, #414345);
      min-height: 100vh;
      margin: 0;
      font-family: 'Segoe UI', 'Arial', sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
    }
    .container {
      background: #2d2d2d;
      border-radius: 20px;
      box-shadow: 0 8px 40px rgba(0,0,0,0.6);
      padding: 30px 40px;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-width: 360px;
    }
    h1 {
      color: #8fd19e;
      margin-bottom: 12px;
      font-size: 2.6rem;
      letter-spacing: 2px;
      text-shadow: 0 1px 3px #0003;
      font-family: 'Segoe UI Black', 'Arial Black', Arial, sans-serif;
    }
    .score {
      color: #fff;
      background: #212121;
      border-radius: 12px;
      padding: 6px 20px;
      font-size: 1.3rem;
      font-weight: bold;
      margin-bottom: 18px;
      letter-spacing: 1.2px;
      box-shadow: 0 1px 2px #0002;
    }
    #gameCanvas {
      background: #202526;
      border-radius: 14px;
      box-shadow: 0 4px 32px #0005;
      display: block;
      margin-bottom: 0;
      border: 2px solid #9adc89;
    }
    .game-over {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: rgba(32,34,36,0.92);
      border-radius: 14px;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      z-index: 99;
      pointer-events: all;
      opacity: 1;
      transition: opacity 0.2s;
    }
    .game-over.hidden {
      pointer-events: none;
      opacity: 0;
    }
    .game-over h2 {
      color: #ef5350;
      font-size: 2.2rem;
      margin: 0 0 6px 0;
      text-shadow: 0 2px 10px #000a;
    }
    .game-over .final-score {
      color: #e0e0e0;
      font-size: 1.3rem;
      margin-bottom: 16px;
    }
    .btn-restart {
      background: linear-gradient(90deg,#8fd19e,#9adc89,#67c23a);
      color: #1b3b23;
      border: none;
      padding: 12px 40px;
      border-radius: 24px;
      font-size: 1.22rem;
      font-weight: bold;
      cursor: pointer;
      box-shadow: 0 2px 12px #0006;
      transition: background 0.2s, transform 0.15s;
      outline: none;
    }
    .btn-restart:hover, .btn-restart:focus {
      background: linear-gradient(90deg, #96eb98, #b6ffb5);
      transform: translateY(-2px) scale(1.03);
    }
    @media (max-width:470px) {
      .container {
        min-width: unset;
        padding:15px 4px;
      }
      #gameCanvas {
        max-width: 98vw;
        height: auto;
      }
    }
    /* Hide canvas outline on focus */
    #gameCanvas:focus { outline: none;}
  </style>
</head>
<body>
  <div class="container" style="position:relative;">
    <h1>Snake</h1>
    <div class="score">Score: <span id="scoreVal">0</span></div>
    <canvas id="gameCanvas" width="400" height="400" tabindex="0" aria-label="Snake game area"></canvas>
    <div id="gameOverBox" class="game-over hidden">
      <h2>Game Over</h2>
      <div class="final-score">Score: <span id="finalScore">0</span></div>
      <button class="btn-restart" id="restartBtn">Play Again</button>
    </div>
  </div>

  <script>
    // ===== ROOT CONFIG ===== //
    const canvas = document.getElementById('gameCanvas');
    const ctx = canvas.getContext('2d');
    const size = 20; // size of one "cell" in px
    const tileCount = canvas.width / size; // for 400px: 20 x 20 grid
    const scoreSpan = document.getElementById('scoreVal');
    const overBox = document.getElementById('gameOverBox');
    const finalScoreSpan = document.getElementById('finalScore');
    const restartBtn = document.getElementById('restartBtn');
    let animationId = null;

    // ======= GAME STATE ======= //
    let snake, direction, nextDirection, food, score, playing, speed, growthLeft;

    function resetGame() {
      snake = [
        {x: 9, y: 10}, // head
        {x: 8, y:10},
        {x: 7, y:10}
      ];
      direction = {x: 1, y:0}; // right
      nextDirection = {...direction};
      spawnFood();
      score = 0;
      scoreSpan.textContent = '0';
      playing = true;
      speed = 100; // ms per frame (~10 FPS)
      growthLeft = 0;
      hideGameOver();
      canvas.focus();
      if(animationId !== null) cancelAnimationFrame(animationId);
      // Start game loop
      setTimeout(gameLoop, speed);
    }

    // ===== GAME DRAWING ===== //
    function drawCell(x, y, color) {
      ctx.fillStyle = color;
      ctx.fillRect(x*size, y*size, size, size);
      // slight border
      ctx.strokeStyle = "#1b3b23";
      ctx.strokeRect(x*size + 1, y*size + 1, size - 2, size - 2);
    }

    function drawSnake() {
      for(let i=0;i<snake.length;i++) {
        drawCell(
          snake[i].x, snake[i].y,
          i === 0 ? "#85ffb7" : "#61c084"
        );
      }
    }

    function drawFood() {
      ctx.beginPath();
      ctx.arc(
        (food.x + 0.5) * size,
        (food.y + 0.5) * size,
        size * .41,
        0, 2*Math.PI
      );
      ctx.fillStyle = "#ef5350";
      ctx.shadowColor = "#ee797a";
      ctx.shadowBlur = 7;
      ctx.fill();
      ctx.shadowBlur = 0;
      ctx.strokeStyle = "#b71c1c";
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.lineWidth = 1;
    }

    function draw() {
      // background
      ctx.fillStyle = "#262a2f";
      ctx.fillRect(0,0,canvas.width,canvas.height);

      // grid (light lines for polish)
      ctx.strokeStyle = "#33433e";
      ctx.lineWidth = 1;
      for(let i=1;i<tileCount;i++){
        ctx.beginPath();
        ctx.moveTo(i*size,0); ctx.lineTo(i*size, canvas.height); ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0,i*size); ctx.lineTo(canvas.width, i*size); ctx.stroke();
      }
      drawFood();
      drawSnake();
    }

    function spawnFood() {
      let valid = false;
      while(!valid) {
        food = {
          x: Math.floor(Math.random()*tileCount),
          y: Math.floor(Math.random()*tileCount),
        };
        // Ensure food not on snake
        valid = !snake.some(seg=>seg.x===food.x&&seg.y===food.y);
      }
    }

    // ====== INPUT HANDLING ====== //
    window.addEventListener('keydown', function(e){
      if(!playing && (e.code.startsWith('Arrow') || e.code==="Space")) {
        // quick restart if not playing
        resetGame();
        return;
      }
      let newDir = null;
      if(e.code === "ArrowUp"    && direction.y!== 1) newDir = {x:0, y:-1};
      else if(e.code === "ArrowDown" && direction.y!== -1) newDir = {x:0, y:1};
      else if(e.code === "ArrowLeft" && direction.x!== 1) newDir = {x:-1, y:0};
      else if(e.code === "ArrowRight"&& direction.x!== -1) newDir = {x:1, y:0};

      if(newDir) {
        nextDirection = newDir;
        e.preventDefault();
      }
    });

    canvas.addEventListener('click', () => canvas.focus());

    // ========== GAME LOOP ========== //
    function gameLoop() {
      if(!playing) return;
      moveSnake();
      if(playing) draw();
      if(playing) {
        animationId = setTimeout(gameLoop, speed);
      }
    }

    function moveSnake() {
      // Move direction only after input processed (prevents double moves per frame)
      direction = {...nextDirection};
      const newHead = {
        x: snake[0].x + direction.x,
        y: snake[0].y + direction.y
      };

      // Collision: wall
      if(newHead.x<0 || newHead.x>=tileCount || newHead.y<0 || newHead.y>=tileCount){
        gameOver();
        return;
      }
      // Collision: self
      if(snake.some(seg=>seg.x===newHead.x&&seg.y===newHead.y)){
        gameOver();
        return;
      }

      snake.unshift(newHead);

      // Food eaten?
      if(newHead.x === food.x && newHead.y === food.y){
        score += 1;
        scoreSpan.textContent = score;
        growthLeft += 1;
        spawnFood();
        // Slightly speed up game, minimum 60ms
        if(speed > 60) speed -= 2.9;
      }
      else if(growthLeft > 0){
        growthLeft -=1;
      } else {
        snake.pop(); // normal movement: remove tail
      }
    }

    // ======= GAME OVER & RESTART ======= //
    function gameOver() {
      playing=false;
      overBox.classList.remove('hidden');
      finalScoreSpan.textContent = score;
    }

    function hideGameOver(){
      overBox.classList.add('hidden');
    }

    restartBtn.addEventListener('click', resetGame);

    // ========== INIT ========= //
    canvas.focus();
    resetGame();
  </script>
</body>
</html>
```

---

**Usage:**
- Save the above as `index.html` and open in your browser.
- Controls: Arrow keys.
- Restart: Click “Play Again” or press any arrow key/space after game over.

Let me know if you want further customization or features!
